    public static IEnumerable<GeneratedMerchant> EnumerateMerchants() => Merchants;

    public static IEnumerable<GeneratedShopRef> EnumerateShops()
    {
        foreach (var merchant in Merchants)
        {
            foreach (var shop in merchant.Shops)
                yield return new GeneratedShopRef(merchant.Name, shop.Name, shop);
        }
    }

    public static IEnumerable<GeneratedShopRef> EnumerateAllShops(bool includeNestedShops = true)
    {
        foreach (var topLevel in EnumerateShops())
        {
            yield return topLevel;

            if (!includeNestedShops)
                continue;

            foreach (var nested in EnumerateNestedShops(topLevel.MerchantName, topLevel.Shop))
                yield return nested;
        }
    }

    public static IEnumerable<GeneratedItemRef> EnumerateItems(bool includeNestedShops = true)
    {
        foreach (var topLevel in EnumerateShops())
        {
            foreach (var item in EnumerateShopItems(topLevel.MerchantName, topLevel.ShopName, topLevel.Shop, includeNestedShops))
                yield return item;
        }
    }

    public static IEnumerable<GeneratedItemRef> EnumerateShopSlotItems(bool includeNestedShops = true)
    {
        foreach (var item in EnumerateItems(includeNestedShops))
        {
            if (item.Item.IsShopSlot)
                yield return item;
        }
    }

    public static IEnumerable<GeneratedItemRef> EnumeratePricedItems(bool includeNestedShops = true)
    {
        foreach (var item in EnumerateItems(includeNestedShops))
        {
            if (!string.IsNullOrWhiteSpace(item.Item.Price))
                yield return item;
        }
    }

    public static IEnumerable<GeneratedItemRef> EnumerateConditionedItems(bool includeNestedShops = true)
    {
        foreach (var item in EnumerateItems(includeNestedShops))
        {
            if (item.Item.Conditions.Count > 0)
                yield return item;
        }
    }

    private static IEnumerable<GeneratedShopRef> EnumerateNestedShops(string merchantName, GeneratedShop shop)
    {
        foreach (var item in shop.Items)
        {
            if (item.NestedShop is null)
                continue;

            yield return new GeneratedShopRef(merchantName, item.NestedShop.Name, item.NestedShop);

            foreach (var nested in EnumerateNestedShops(merchantName, item.NestedShop))
                yield return nested;
        }
    }

    private static IEnumerable<GeneratedItemRef> EnumerateShopItems(string merchantName, string rootShopName, GeneratedShop shop, bool includeNestedShops)
    {
        foreach (var item in shop.Items)
        {
            yield return new GeneratedItemRef(merchantName, rootShopName, shop.Name, item);

            if (includeNestedShops && item.NestedShop is not null)
            {
                foreach (var nestedItem in EnumerateShopItems(merchantName, rootShopName, item.NestedShop, includeNestedShops))
                    yield return nestedItem;
            }
        }
    }
}

public sealed record GeneratedMerchant(string Name, IReadOnlyList<GeneratedShop> Shops);

public sealed record GeneratedShop(string Name, IReadOnlyList<GeneratedItem> Items);

public sealed record GeneratedItem(string Name, string? Price, IReadOnlyList<string> Conditions, bool IsShopSlot, GeneratedShop? NestedShop);

public sealed record GeneratedShopRef(string MerchantName, string ShopName, GeneratedShop Shop);

public sealed record GeneratedItemRef(string MerchantName, string RootShopName, string ShopName, GeneratedItem Item)
{
    public string ItemName => Item.Name;
    public string? Price => Item.Price;
    public IReadOnlyList<string> Conditions => Item.Conditions;
    public bool IsShopSlot => Item.IsShopSlot;
    public GeneratedShop? NestedShop => Item.NestedShop;
}
